// Get AI output and upstream data
const aiOutput = $input.first().json.text;
const resumeText = $('key extractions').first().json.resume_text;
const userId = $('key extractions').first().json.user_id;
const fileUrl = $('key extractions').first().json.file_url;

// Strip markdown code blocks if present
let jsonStr = aiOutput;
if (jsonStr.includes('```json')) {
  jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '');
} else if (jsonStr.includes('```')) {
  jsonStr = jsonStr.replace(/```\n?/g, '');
}
jsonStr = jsonStr.trim();

// Parse the JSON
let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // Try to extract JSON from the string
  const match = jsonStr.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse AI output as JSON: ' + e.message);
  }
}

// Question ID mappings
const QUESTION_IDS = {
  name: '11111111-1111-1111-1111-11111111111a',
  region: '11111111-1111-1111-1111-111111111114',
  education: '11111111-1111-1111-1111-111111111116',
  study_subject: '11111111-1111-1111-1111-111111111117',
  years_experience: '11111111-1111-1111-1111-111111111118',
  career_situation: '11111111-1111-1111-1111-111111111119',
  career_history: '11111111-1111-1111-1111-111111111110',
  achievement: '11111111-1111-1111-1111-11111111111f',
  interests: '11111111-1111-1111-1111-111111111120'
};

// Build skills and achievements combined data
const skillsAndAchievements = {
  top_skills: parsed.top_skills || [],
  certifications: parsed.certifications || [],
  achievements: parsed.achievements || []
};

// Build the survey data mapped to question IDs
const surveyData = {};

if (parsed.name) {
  surveyData[QUESTION_IDS.name] = { value: parsed.name };
}
if (parsed.region) {
  surveyData[QUESTION_IDS.region] = { value: parsed.region };
}
if (parsed.education) {
  surveyData[QUESTION_IDS.education] = { value: parsed.education };
}
if (parsed.study_subject) {
  surveyData[QUESTION_IDS.study_subject] = { value: parsed.study_subject };
}
if (parsed.years_experience !== undefined) {
  surveyData[QUESTION_IDS.years_experience] = { value: String(parsed.years_experience) };
}
if (parsed.career_situation) {
  surveyData[QUESTION_IDS.career_situation] = { value: parsed.career_situation };
}
if (parsed.career_history && parsed.career_history.length > 0) {
  surveyData[QUESTION_IDS.career_history] = { value: parsed.career_history };
}
if (skillsAndAchievements.top_skills.length > 0 || skillsAndAchievements.achievements.length > 0) {
  surveyData[QUESTION_IDS.achievement] = { value: skillsAndAchievements };
}
if (parsed.interests) {
  surveyData[QUESTION_IDS.interests] = { value: parsed.interests };
}

return [{
  json: {
    user_id: userId,
    file_url: fileUrl,
    resume_text: resumeText,
    parsed_raw: parsed,
    resume_parsed_data: surveyData
  }
}];
